58	/// Secondary entry point: report any of `lemma_names` that are not declared in
59	/// the theory. NOTE: this entry point's exact render string could not be
60	/// observed through the file oracle; the set-difference logic is verified but
61	/// the message text is a documented gap (see BEHAVIOR.md).
62	pub fn check_if_lemmas_in_theory(lemma_names: &[String], thy: &Theory) -> WfReport {
63	    let present = checks::theory_lemma_names(thy);
64	    let mut out = Vec::new();
65	    for name in lemma_names {
66	        if !present.contains(name) {
67	            out.push(WfError::new(
68	                "Lemmas",
69	                format!("lemma `{}' referenced but not present in theory", name),
70	            ));
71	        }
72	    }
73	    out
74	}
