8	// ---- Topic strings (exact, including significant whitespace) ----
9	pub const T_UNBOUND: &str = "Unbound variables";
10	pub const T_PUBNAMES: &str = "Public constants with mismatching capitalization";
11	pub const T_SORTS: &str = "Variable with mismatching sorts or capitalization";
12	pub const T_RESERVED: &str = "Reserved names";
13	pub const T_FR: &str = "Fr facts must only use a fresh- or a msg-variable";
14	pub const T_SPECIAL: &str = "Special facts";
15	pub const T_ARITY: &str = "Fact arity issues";
16	pub const T_MULT: &str = "Fact multiplicity issues";
17	pub const T_LHSRHS: &str = "Facts occur in the left-hand-side but not in any right-hand-side ";
18	pub const T_FORMULA_TERMS: &str = "Formula terms";
19	pub const T_GUARD: &str = " Formula guardedness";
20	pub const T_NAT: &str = "Nat Sorts";
21	pub const T_SUBTERM: &str = "Subterm Convergence Warning";
22	
23	/// Reserved fact names (used as protocol facts -> "Reserved names").
24	const RESERVED_FACTS: &[&str] = &["K", "KU", "KD"];
25	/// Special I/O facts handled by the special-fact / Fr checks.
26	const SPECIAL_FACTS: &[&str] = &["In", "Out", "Fr"];
27	
28	fn is_reserved(name: &str) -> bool {
29	    RESERVED_FACTS.contains(&name)
30	}
31	fn is_special(name: &str) -> bool {
32	    SPECIAL_FACTS.contains(&name)
33	}
34	fn is_builtin_factname(name: &str) -> bool {
35	    is_reserved(name) || is_special(name)
36	}
