38	// ---------------------------------------------------------------------------
39	// AST traversal helpers
40	// ---------------------------------------------------------------------------
41	
42	/// The protocol rules of a theory (excludes intruder rules).
43	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
44	    thy.items
45	        .iter()
46	        .filter_map(|it| match it {
47	            TheoryItem::Rule(r) => Some(r),
48	            _ => None,
49	        })
50	        .collect()
51	}
