129	// ---------------------------------------------------------------------------
130	// 1. Unbound variables
131	// ---------------------------------------------------------------------------
132	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
133	    let mut entries: Vec<String> = Vec::new();
134	    for r in protocol_rules(thy) {
135	        // Bound = variables in premises plus let-bound variables.
136	        let mut bound: Vec<VarSpec> = Vec::new();
137	        collect_facts_vars(&r.premises, &mut bound);
138	        for lb in &r.let_block {
139	            collect_term_vars(&lb.var, &mut bound);
140	        }
141	        let bound: std::collections::HashSet<(String, u64, i32)> =
142	            bound.iter().map(var_key).collect();
143	
144	        // Used = variables in actions, conclusions, embedded restrictions,
145	        // and the right-hand-sides of let bindings.
146	        let mut used: Vec<VarSpec> = Vec::new();
147	        collect_facts_vars(&r.actions, &mut used);
148	        collect_facts_vars(&r.conclusions, &mut used);
149	        for lb in &r.let_block {
150	            collect_term_vars(&lb.value, &mut used);
151	        }
152	
153	        let mut unbound: Vec<VarSpec> = used
154	            .into_iter()
155	            .filter(var_needs_binding)
156	            .filter(|v| !bound.contains(&var_key(v)))
157	            .collect();
158	        unbound = dedup_vars(unbound);
159	        // Report order: by base name then index.
160	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
161	
162	        if !unbound.is_empty() {
163	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
164	            entries.push(format!(
165	                "  rule `{}' has unbound variables: \n    {}",
166	                r.name,
167	                names.join(", ")
168	            ));
169	        }
170	    }
171	    if entries.is_empty() {
172	        vec![]
173	    } else {
174	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
175	    }
176	}
