178	// ---------------------------------------------------------------------------
179	// 3. Variable with mismatching sorts or capitalization
180	// ---------------------------------------------------------------------------
181	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
182	    let mut rule_entries: Vec<String> = Vec::new();
183	    for r in protocol_rules(thy) {
184	        let mut vars: Vec<VarSpec> = Vec::new();
185	        collect_facts_vars(&r.premises, &mut vars);
186	        collect_facts_vars(&r.actions, &mut vars);
187	        collect_facts_vars(&r.conclusions, &mut vars);
188	
189	        // Group by lowercased base name; a group with >1 distinct variant
190	        // (prefix+name, ignoring index) is a conflict.
191	        let mut groups: Vec<(String, Vec<String>)> = Vec::new(); // (lc key, variants)
192	        for v in &vars {
193	            let key = v.name.to_lowercase();
194	            let variant = variant_repr(v);
195	            match groups.iter_mut().find(|(k, _)| *k == key) {
196	                Some((_, variants)) => {
197	                    if !variants.contains(&variant) {
198	                        variants.push(variant);
199	                    }
200	                }
201	                None => groups.push((key, vec![variant])),
202	            }
203	        }
204	        let mut conflicts: Vec<Vec<String>> = groups
205	            .into_iter()
206	            .filter(|(_, vs)| vs.len() > 1)
207	            .map(|(_, mut vs)| {
208	                vs.sort();
209	                vs
210	            })
211	            .collect();
212	        if conflicts.is_empty() {
213	            continue;
214	        }
215	        // deterministic ordering of groups within a rule
216	        conflicts.sort();
217	        let mut body = format!("  rule `{}': ", r.name);
218	        for (i, variants) in conflicts.iter().enumerate() {
219	            body.push_str(&format!("\n    {}. {}", i + 1, variants.join(", ")));
220	        }
221	        rule_entries.push(body);
222	    }
223	    if rule_entries.is_empty() {
224	        return vec![];
225	    }
226	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
227	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
228	    vec![WfError::new(T_SORTS, msg)]
229	}
230	
231	/// A variable's sort+name representation without the numeric index.
232	fn variant_repr(v: &VarSpec) -> String {
233	    let prefix = match v.sort {
234	        SortHint::Fresh => "~",
235	        SortHint::Pub => "$",
236	        SortHint::Nat => "%",
237	        SortHint::Node => "#",
238	        _ => "",
239	    };
240	    format!("{}{}", prefix, v.name)
241	}
