243	// ---------------------------------------------------------------------------
244	// 4. Reserved names
245	// ---------------------------------------------------------------------------
246	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
247	    let mut entries: Vec<String> = Vec::new();
248	    for r in protocol_rules(thy) {
249	        // On the left/right the reserved set is {K,KU,KD}; in the middle
250	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
251	        for (facts, phrase, middle) in [
252	            (&r.premises, "left-hand-side", false),
253	            (&r.actions, "the middle", true),
254	            (&r.conclusions, "the right-hand-side", false),
255	        ] {
256	            let hits: Vec<&Fact> = facts
257	                .iter()
258	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
259	                .collect();
260	            if hits.is_empty() {
261	                continue;
262	            }
263	            let rendered: Vec<String> = hits.iter().map(|f| pp_fact(f)).collect();
264	            entries.push(format!(
265	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
266	                r.name,
267	                phrase,
268	                rendered.join(", ")
269	            ));
270	        }
271	    }
272	    if entries.is_empty() {
273	        vec![]
274	    } else {
275	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
276	    }
277	}
