279	// ---------------------------------------------------------------------------
280	// 5. Fr facts must only use a fresh- or a msg-variable
281	// ---------------------------------------------------------------------------
282	pub fn fr_facts(thy: &Theory) -> Vec<WfError> {
283	    let mut entries: Vec<String> = Vec::new();
284	    for r in protocol_rules(thy) {
285	        for facts in [&r.premises, &r.conclusions] {
286	            for f in facts {
287	                if f.name != "Fr" {
288	                    continue;
289	                }
290	                let ok = f.args.len() == 1
291	                    && matches!(
292	                        &f.args[0],
293	                        Term::Var(v) if matches!(v.sort, SortHint::Fresh | SortHint::Msg | SortHint::Untagged)
294	                    );
295	                if !ok {
296	                    entries.push(format!("  rule `{}' fact: {}", r.name, pp_fact(f)));
297	                }
298	            }
299	        }
300	    }
301	    if entries.is_empty() {
302	        vec![]
303	    } else {
304	        vec![WfError::new(T_FR, entries.join("\n  \n"))]
305	    }
306	}
