308	// ---------------------------------------------------------------------------
309	// 6. Special facts (disallowed I/O facts in wrong position)
310	// ---------------------------------------------------------------------------
311	pub fn special_facts(thy: &Theory) -> Vec<WfError> {
312	    let mut entries: Vec<String> = Vec::new();
313	    for r in protocol_rules(thy) {
314	        // Premise side: `Out` is disallowed.
315	        let lhs: Vec<String> = r
316	            .premises
317	            .iter()
318	            .filter(|f| f.name == "Out")
319	            .map(|f| pp_fact(f))
320	            .collect();
321	        if !lhs.is_empty() {
322	            entries.push(format!(
323	                "  rule `{}' uses disallowed facts on left-hand-side:\n    {}",
324	                r.name,
325	                lhs.join(", ")
326	            ));
327	        }
328	        // Conclusion side: `In` and `Fr` are disallowed.
329	        let rhs: Vec<String> = r
330	            .conclusions
331	            .iter()
332	            .filter(|f| f.name == "In" || f.name == "Fr")
333	            .map(|f| pp_fact(f))
334	            .collect();
335	        if !rhs.is_empty() {
336	            entries.push(format!(
337	                "  rule `{}' uses disallowed facts on right-hand-side:\n    {}",
338	                r.name,
339	                rhs.join(", ")
340	            ));
341	        }
342	    }
343	    if entries.is_empty() {
344	        vec![]
345	    } else {
346	        vec![WfError::new(T_SPECIAL, entries.join("\n  \n"))]
347	    }
348	}
