353	
354	struct FactUse {
355	    rule: String,
356	    arity: usize,
357	    persistent: bool,
358	    pp: String,
359	}
360	
361	/// Gather every fact occurrence in protocol rules (name -> uses), in source
362	/// order.
363	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
364	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
365	    for r in protocol_rules(thy) {
366	        for facts in [&r.premises, &r.actions, &r.conclusions] {
367	            for f in facts {
368	                let entry = FactUse {
369	                    rule: r.name.clone(),
370	                    arity: f.args.len(),
371	                    persistent: f.persistent,
372	                    pp: pp_fact(f),
373	                };
374	                match map.iter_mut().find(|(n, _)| *n == f.name) {
375	                    Some((_, uses)) => uses.push(entry),
376	                    None => map.push((f.name.clone(), vec![entry])),
377	                }
378	            }
379	        }
380	    }
381	    map
382	}
383	
384	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
385	    // conflicts: (lowercased fact name, item lines) already ordered.
386	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
387	    for (i, (lname, items)) in conflicts.iter().enumerate() {
388	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
389	        if i == 0 {
390	            body.push_str("\n\n");
391	        } else {
392	            body.push('\n');
393	        }
394	        body.push_str(&block);
395	    }
396	    body
397	}
398	
399	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
400	    let uses = gather_fact_uses(thy);
401	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
402	    for (name, us) in &uses {
403	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
404	        if arities.len() < 2 {
405	            continue;
406	        }
407	        // one item per distinct (rule, arity), first pp kept, source order.
408	        let mut seen: Vec<(String, usize)> = Vec::new();
409	        let mut items: Vec<String> = Vec::new();
410	        for u in us {
411	            let k = (u.rule.clone(), u.arity);
412	            if seen.contains(&k) {
413	                continue;
414	            }
415	            seen.push(k);
416	            let n = items.len() + 1;
417	            items.push(format!(
418	                "    {}. Rule `{}', arity {}\n         {}",
419	                n, u.rule, u.arity, u.pp
420	            ));
421	        }
422	        conflicts.push((name.to_lowercase(), items));
423	    }
424	    if conflicts.is_empty() {
425	        return vec![];
426	    }
427	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
428	    let msg = render_fact_blocks(
429	        &conflicts,
430	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
431	        "Check the arguments of your facts.",
432	    );
433	    vec![WfError::new(T_ARITY, msg)]
434	}
