436	pub fn fact_multiplicity(thy: &Theory) -> Vec<WfError> {
437	    let uses = gather_fact_uses(thy);
438	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
439	    for (name, us) in &uses {
440	        let mults: std::collections::BTreeSet<bool> = us.iter().map(|u| u.persistent).collect();
441	        if mults.len() < 2 {
442	            continue;
443	        }
444	        let mut seen: Vec<(String, bool)> = Vec::new();
445	        let mut items: Vec<String> = Vec::new();
446	        for u in us {
447	            let k = (u.rule.clone(), u.persistent);
448	            if seen.contains(&k) {
449	                continue;
450	            }
451	            seen.push(k);
452	            let n = items.len() + 1;
453	            let m = if u.persistent { "Persistent" } else { "Linear" };
454	            items.push(format!(
455	                "    {}. Rule `{}', multiplicity (persistence) {}\n         {}",
456	                n, u.rule, m, u.pp
457	            ));
458	        }
459	        conflicts.push((name.to_lowercase(), items));
460	    }
461	    if conflicts.is_empty() {
462	        return vec![];
463	    }
464	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
465	    let msg = render_fact_blocks(
466	        &conflicts,
467	        "Same fact is used with different multiplicities, i.e., !Fact() (Persistent fact) exists along with Fact() (Linear) in your rules. ",
468	        "Check the multiplicity (persistence) of your facts.",
469	    );
470	    vec![WfError::new(T_MULT, msg)]
471	}
