473	// ---------------------------------------------------------------------------
474	// 9. Facts occur in the left-hand-side but not in any right-hand-side
475	// ---------------------------------------------------------------------------
476	
477	#[derive(Clone)]
478	struct FactId {
479	    name: String,
480	    arity: usize,
481	    persistent: bool,
482	    rule: String,
483	}
484	
485	impl FactId {
486	    fn ident(&self) -> (String, usize, bool) {
487	        (self.name.clone(), self.arity, self.persistent)
488	    }
489	    fn render(&self) -> String {
490	        format!(
491	            "in rule \"{}\":  factName `{}' arity: {} multiplicity: {}",
492	            self.rule,
493	            self.name,
494	            self.arity,
495	            if self.persistent { "Persistent" } else { "Linear" }
496	        )
497	    }
498	}
499	
500	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
501	    let mut lhs: Vec<FactId> = Vec::new();
502	    let mut rhs: Vec<FactId> = Vec::new();
503	    for r in protocol_rules(thy) {
504	        for f in &r.premises {
505	            if is_builtin_factname(&f.name) {
506	                continue;
507	            }
508	            lhs.push(FactId {
509	                name: f.name.clone(),
510	                arity: f.args.len(),
511	                persistent: f.persistent,
512	                rule: r.name.clone(),
513	            });
514	        }
515	        for f in &r.conclusions {
516	            if is_builtin_factname(&f.name) {
517	                continue;
518	            }
519	            rhs.push(FactId {
520	                name: f.name.clone(),
521	                arity: f.args.len(),
522	                persistent: f.persistent,
523	                rule: r.name.clone(),
524	            });
525	        }
526	    }
527	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
528	        rhs.iter().map(|f| f.ident()).collect();
529	
530	    // LHS-only identities, first occurrence, in source order.
531	    let mut seen: Vec<(String, usize, bool)> = Vec::new();
532	    let mut items: Vec<String> = Vec::new();
533	    for f in &lhs {
534	        if rhs_idents.contains(&f.ident()) || seen.contains(&f.ident()) {
535	            continue;
536	        }
537	        seen.push(f.ident());
538	        let n = items.len() + 1;
539	        let mut line = format!("  {}. {}", n, f.render());
540	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
541	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
542	        }
543	        items.push(line);
544	    }
545	    if items.is_empty() {
546	        vec![]
547	    } else {
548	        vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
549	    }
550	}
551	
552	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
553	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
554	    let mut best: Option<(usize, &FactId)> = None;
555	    for f in rhs {
556	        let d = edit_distance(name, &f.name);
557	        match best {
558	            Some((bd, _)) if d >= bd => {}
559	            _ => best = Some((d, f)),
560	        }
561	    }
562	    match best {
563	        Some((d, f)) if d <= 3 => Some(f),
564	        _ => None,
565	    }
566	}
567	
568	fn edit_distance(a: &str, b: &str) -> usize {
569	    let a: Vec<char> = a.chars().collect();
570	    let b: Vec<char> = b.chars().collect();
571	    let mut prev: Vec<usize> = (0..=b.len()).collect();
572	    let mut cur = vec![0usize; b.len() + 1];
573	    for i in 1..=a.len() {
574	        cur[0] = i;
575	        for j in 1..=b.len() {
576	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
577	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
578	        }
579	        std::mem::swap(&mut prev, &mut cur);
580	    }
581	    prev[b.len()]
582	}
