585	// 2. Public constants with mismatching capitalization (public-names report)
586	// ---------------------------------------------------------------------------
587	
588	pub fn public_names_report(thy: &Theory) -> Vec<WfError> {
589	    let mut pairs: Vec<(String, String)> = Vec::new(); // (constName, ruleName)
590	    for r in protocol_rules(thy) {
591	        let mut names: Vec<String> = Vec::new();
592	        for facts in [&r.premises, &r.actions, &r.conclusions] {
593	            for f in facts {
594	                for a in &f.args {
595	                    collect_pub_lits(a, &mut names);
596	                }
597	            }
598	        }
599	        for n in names {
600	            let pair = (n, r.name.clone());
601	            if !pairs.contains(&pair) {
602	                pairs.push(pair);
603	            }
604	        }
605	    }
606	    public_names_report_from_pairs(pairs)
607	}
608	
609	pub fn public_names_report_from_pairs(pairs: Vec<(String, String)>) -> Vec<WfError> {
610	    // Group by lowercased constant name, preserving first-seen order.
611	    let mut groups: Vec<(String, Vec<(String, String)>)> = Vec::new();
612	    for (name, rule) in &pairs {
613	        let key = name.to_lowercase();
614	        match groups.iter_mut().find(|(k, _)| *k == key) {
615	            Some((_, v)) => v.push((name.clone(), rule.clone())),
616	            None => groups.push((key, vec![(name.clone(), rule.clone())])),
617	        }
618	    }
619	    let mut items: Vec<String> = Vec::new();
620	    for (_, occ) in &groups {
621	        let distinct: std::collections::BTreeSet<&String> = occ.iter().map(|(n, _)| n).collect();
622	        if distinct.len() < 2 {
623	            continue; // no capitalization conflict
624	        }
625	        // Group occurrences by rule, preserving first-seen rule order.
626	        let mut by_rule: Vec<(String, Vec<String>)> = Vec::new();
627	        for (n, rule) in occ {
628	            match by_rule.iter_mut().find(|(rr, _)| rr == rule) {
629	                Some((_, ns)) => {
630	                    if !ns.contains(n) {
631	                        ns.push(n.clone());
632	                    }
633	                }
634	                None => by_rule.push((rule.clone(), vec![n.clone()])),
635	            }
636	        }
637	        let locs: Vec<String> = by_rule
638	            .into_iter()
639	            .map(|(rule, mut ns)| {
640	                ns.sort();
641	                let quoted: Vec<String> = ns.iter().map(|n| format!("'{}'", n)).collect();
642	                format!("rule \"{}\":  name {}", rule, quoted.join(", "))
643	            })
644	            .collect();
645	        let n = items.len() + 1;
646	        items.push(format!("  {}. {}", n, locs.join(", ")));
647	    }
648	    if items.is_empty() {
649	        return vec![];
650	    }
651	    let header = "Identifiers are case-sensitive, mismatched capitalizations are considered as different, i.e., 'ID' is different from 'id'. Check the capitalization of your identifiers.";
652	    let msg = format!("{}\n\n{}", header, items.join("\n  \n"));
653	    vec![WfError::new(T_PUBNAMES, msg)]
654	}
