656	// ---------------------------------------------------------------------------
657	// 10. Formula terms (free variables in lemma / restriction formulas)
658	// ---------------------------------------------------------------------------
659	
660	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
661	
662	fn free_vars_formula(f: &Formula, bound: &mut Vec<(String, i32)>, out: &mut Vec<VarSpec>) {
663	    match f {
664	        Formula::False | Formula::True => {}
665	        Formula::Atom(a) => {
666	            let mut vs = Vec::new();
667	            atom_vars(a, &mut vs);
668	            for v in vs {
669	                let k = (v.name.clone(), sort_rank(v.sort));
670	                if !bound.contains(&k) {
671	                    out.push(v);
672	                }
673	            }
674	        }
675	        Formula::Not(g) => free_vars_formula(g, bound, out),
676	        Formula::And(a, b)
677	        | Formula::Or(a, b)
678	        | Formula::Implies(a, b)
679	        | Formula::Iff(a, b) => {
680	            free_vars_formula(a, bound, out);
681	            free_vars_formula(b, bound, out);
682	        }
683	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
684	            let added: Vec<(String, i32)> =
685	                vs.iter().map(|v| (v.name.clone(), sort_rank(v.sort))).collect();
686	            let n = added.len();
687	            bound.extend(added);
688	            free_vars_formula(g, bound, out);
689	            for _ in 0..n {
690	                bound.pop();
691	            }
692	        }
693	    }
694	}
695	
696	fn atom_vars(a: &Atom, out: &mut Vec<VarSpec>) {
697	    match a {
698	        Atom::Eq(x, y)
699	        | Atom::Less(x, y)
700	        | Atom::LessMset(x, y)
701	        | Atom::Subterm(x, y) => {
702	            collect_term_vars(x, out);
703	            collect_term_vars(y, out);
704	        }
705	        Atom::Action(f, t) => {
706	            collect_fact_vars(f, out);
707	            collect_term_vars(t, out);
708	        }
709	        Atom::Last(t) => collect_term_vars(t, out),
710	        Atom::Pred(f) => collect_fact_vars(f, out),
711	    }
712	}
713	
714	fn formula_terms_entry(entity: &str, name: &str, free: &[VarSpec]) -> String {
715	    let terms: Vec<String> = free.iter().map(|v| format!("`Free {}'", pp_var(v))).collect();
716	    let head = if terms.len() == 1 {
717	        format!(
718	            "  {} `{}' uses terms of the wrong form: {}",
719	            entity, name, terms[0]
720	        )
721	    } else {
722	        format!(
723	            "  {} `{}' uses terms of the wrong form:\n    {}",
724	            entity,
725	            name,
726	            terms.join(", ")
727	        )
728	    };
729	    format!("{}\n  \n{}", head, FORMULA_TERMS_HELP)
730	}
731	
732	pub fn formula_terms(thy: &Theory) -> Vec<WfError> {
733	    let mut entries: Vec<String> = Vec::new();
734	    for it in &thy.items {
735	        let (entity, name, formula) = match it {
736	            TheoryItem::Lemma(l) => ("Lemma", &l.name, &l.formula),
737	            TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) => {
738	                ("Restriction", &r.name, &r.formula)
739	            }
740	            _ => continue,
741	        };
742	        let mut bound = Vec::new();
743	        let mut free = Vec::new();
744	        free_vars_formula(formula, &mut bound, &mut free);
745	        let free = dedup_vars(free);
746	        if !free.is_empty() {
747	            entries.push(formula_terms_entry(entity, name, &free));
748	        }
749	    }
750	    if entries.is_empty() {
751	        vec![]
752	    } else {
753	        vec![WfError::new(T_FORMULA_TERMS, entries.join("\n"))]
754	    }
755	}
