9	// ---- AST builders ---------------------------------------------------------
10	
11	fn var(name: &str, sort: SortHint) -> VarSpec {
12	    VarSpec { name: name.into(), idx: 0, sort, typ: None }
13	}
14	fn mv(name: &str) -> Term { Term::Var(var(name, SortHint::Msg)) }
15	fn fresh(name: &str) -> Term { Term::Var(var(name, SortHint::Fresh)) }
16	fn pub_(name: &str) -> Term { Term::Var(var(name, SortHint::Pub)) }
17	fn node(name: &str) -> Term { Term::Var(var(name, SortHint::Node)) }
18	fn pl(name: &str) -> Term { Term::PubLit(name.into()) }
19	
20	fn fact(name: &str, args: Vec<Term>) -> Fact {
21	    Fact { persistent: false, name: name.into(), args, annotations: vec![] }
22	}
23	fn pfact(name: &str, args: Vec<Term>) -> Fact {
24	    Fact { persistent: true, name: name.into(), args, annotations: vec![] }
25	}
26	
27	fn rule(name: &str, prem: Vec<Fact>, act: Vec<Fact>, concl: Vec<Fact>) -> TheoryItem {
28	    TheoryItem::Rule(Rule {
29	        name: name.into(),
30	        modulo: None,
31	        attributes: vec![],
32	        let_block: vec![],
33	        premises: prem,
34	        actions: act,
35	        conclusions: concl,
36	        embedded_restrictions: vec![],
37	        variants: vec![],
38	        left_right: None,
39	    })
40	}
41	
42	fn lemma(name: &str, formula: Formula) -> TheoryItem {
43	    TheoryItem::Lemma(Lemma {
44	        name: name.into(),
45	        modulo: None,
46	        attributes: vec![],
47	        trace_quantifier: TraceQuantifier::AllTraces,
48	        formula,
49	        proof: None,
50	        plaintext: String::new(),
51	    })
52	}
53	
54	fn theory(name: &str, items: Vec<TheoryItem>) -> Theory {
55	    Theory { is_diff: false, name: name.into(), configuration: None, items }
56	}
