58	/// Assert render_report(check_theory(thy)) equals the oracle fixture.
59	fn expect(thy: &Theory, fixture: &str) {
60	    let got = render_report(&check_theory(thy));
61	    let want = format!("/*\n{}", fixture.trim_end_matches('\n'));
62	    assert_eq!(got, want, "\n--- got ---\n{}\n--- want ---\n{}", got, want);
63	}
