/// Render a fact: optional `!` for persistent, then `Name( args )`.
/// Empty argument list renders as `Name( )`.
pub fn pp_fact(f: &Fact) -> String {
    let bang = if f.persistent { "!" } else { "" };
    if f.args.is_empty() {
        format!("{}{}( )", bang, f.name)
    } else {
