fn free_vars_formula(f: &Formula, bound: &mut Vec<(String, i32)>, out: &mut Vec<VarSpec>) {
    match f {
        Formula::False | Formula::True => {}
        Formula::Atom(a) => {
            let mut vs = Vec::new();
            atom_vars(a, &mut vs);
            for v in vs {
                let k = (v.name.clone(), sort_rank(v.sort));
                if !bound.contains(&k) {
                    out.push(v);
                }
            }
        }
        Formula::Not(g) => free_vars_formula(g, bound, out),
        Formula::And(a, b)
        | Formula::Or(a, b)
        | Formula::Implies(a, b)
        | Formula::Iff(a, b) => {
            free_vars_formula(a, bound, out);
            free_vars_formula(b, bound, out);
        }
        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
            let added: Vec<(String, i32)> =
                vs.iter().map(|v| (v.name.clone(), sort_rank(v.sort))).collect();
            let n = added.len();
            bound.extend(added);
            free_vars_formula(g, bound, out);
            for _ in 0..n {
                bound.pop();
            }
        }
    }
}

